import * as t from "io-ts";
import { VoteDelegationIntent } from "./voteDelegationIntent";

/**
 * @title ADA Vote Delegation Intent
 *
 * @description The intent used for delegating ADA voting to a DRep
 *
 * @param {string} dRepId The identifier for a DRep
 */
export const AdaVoteDelegationIntent = t.intersection([
  VoteDelegationIntent,
  t.type({
    dRepId: t.string,
  }),
]);

export type AdaVoteDelegationIntent = t.TypeOf<typeof AdaVoteDelegationIntent>;
